77	func lowestPrice(hs []*handsetpb.Handset) (*sharedmodel.MobileMoney, error) {
78		var minPence int32
79		var currency string
80		for _, h := range hs {
81			pence, err := parsePenceFromMoney(h.GetRentalPrice().GetAmount())
82			if err != nil {
83				return nil, fmt.Errorf("invalid rental price for handset %s: %w", h.GetId(), err)
84			}
85			if pence < 0 {
86				return nil, fmt.Errorf("invalid rental price for handset %s: negative amount", h.GetId())
87			}
88			if minPence == 0 || pence < minPence {
89				minPence = pence
90				currency = h.GetRentalPrice().GetCurrency()
91			}
92		}
93		return &sharedmodel.MobileMoney{
94			Amount:   fmt.Sprintf("%.2f", float64(minPence)/100),
95			Currency: currency,
96		}, nil
97	}
