99	func uniqueValues(hs []*handsetpb.Handset, get func(*handsetpb.Handset) string) []string {
100		seen := map[string]bool{}
101		var vals []string
102		for _, h := range hs {
103			if v := get(h); v != "" && !seen[v] {
104				seen[v] = true
105				vals = append(vals, v)
106			}
107		}
108		return vals
109	}
